2400   Value *LHS = Inst.getOperand(0), *RHS = Inst.getOperand(1);
2401   auto CreateBinOpSplice = [&](Value *X, Value *Y, Value *Offset) {
2402     Value *V = Builder.CreateBinOp(Inst.getOpcode(), X, Y, Inst.getName());
