2426   // -> splice(Op(LHSSplat, V2), poison, offset)
2427   else if (isSplatValue(LHS) &&
2428            match(RHS, m_OneUse(m_Intrinsic<SpliceID>(m_Value(V2), m_Poison(),
2429                                                      m_Value(Offset)))))
