1979   for (unsigned i = 0; i != NumPHIValues; ++i) {
1980     Value *InVal = PN->getIncomingValue(i);
1981     BasicBlock *InBB = PN->getIncomingBlock(i);
1982 
1983     if (auto *NewVal = simplifyInstructionWithPHI(I, PN, InVal, InBB, DL, SQ)) {
