1929 Instruction *InstCombinerImpl::foldOpIntoPhi(Instruction &I, PHINode *PN,
1930                                              bool AllowMultipleUses) {
1931   unsigned NumPHIValues = PN->getNumIncomingValues();
1932   if (NumPHIValues == 0)
