1538 Value *InstCombinerImpl::takeLog2(Value *Op, unsigned Depth, bool AssumeNonZero,
1539                                   bool DoFold) {
1540   auto IfFold = [DoFold](function_ref<Value *()> Fn) {
1541     if (!DoFold)
1542       return reinterpret_cast<Value *>(-1);
1543     return Fn();
1544   };
1545 
1546   // FIXME: assert that Op1 isn't/doesn't contain undef.
1547 
1548   // log2(2^C) -> C
1549   if (match(Op, m_Power2()))
1550     return IfFold([&]() {
1551       Constant *C = ConstantExpr::getExactLogBase2(cast<Constant>(Op));
1552       if (!C)
1553         llvm_unreachable("Failed to constant fold udiv -> logbase2");
1554       return C;
1555     });
1556 
1557   // The remaining tests are all recursive, so bail out if we hit the limit.
1558   if (Depth++ == MaxAnalysisRecursionDepth)
1559     return nullptr;
1560 
1561   // log2(zext X) -> zext log2(X)
1562   // FIXME: Require one use?
1563   Value *X, *Y;
1564   if (match(Op, m_ZExt(m_Value(X))))
1565     if (Value *LogX = takeLog2(X, Depth, AssumeNonZero, DoFold))
1566       return IfFold([&]() { return Builder.CreateZExt(LogX, Op->getType()); });
1567 
1568   // log2(trunc x) -> trunc log2(X)
1569   // FIXME: Require one use?
1570   if (match(Op, m_Trunc(m_Value(X)))) {
1571     auto *TI = cast<TruncInst>(Op);
1572     if (AssumeNonZero || TI->hasNoUnsignedWrap())
1573       if (Value *LogX = takeLog2(X, Depth, AssumeNonZero, DoFold))
1574         return IfFold([&]() {
1575           return Builder.CreateTrunc(LogX, Op->getType(), "",
1576                                      /*IsNUW=*/TI->hasNoUnsignedWrap());
1577         });
1578   }
1579 
1580   // log2(X << Y) -> log2(X) + Y
1581   // FIXME: Require one use unless X is 1?
1582   if (match(Op, m_Shl(m_Value(X), m_Value(Y)))) {
1583     auto *BO = cast<OverflowingBinaryOperator>(Op);
1584     // nuw will be set if the `shl` is trivially non-zero.
1585     if (AssumeNonZero || BO->hasNoUnsignedWrap() || BO->hasNoSignedWrap())
1586       if (Value *LogX = takeLog2(X, Depth, AssumeNonZero, DoFold))
1587         return IfFold([&]() { return Builder.CreateAdd(LogX, Y); });
1588   }
1589 
1590   // log2(X >>u Y) -> log2(X) - Y
1591   // FIXME: Require one use?
1592   if (match(Op, m_LShr(m_Value(X), m_Value(Y)))) {
1593     auto *PEO = cast<PossiblyExactOperator>(Op);
1594     if (AssumeNonZero || PEO->isExact())
1595       if (Value *LogX = takeLog2(X, Depth, AssumeNonZero, DoFold))
1596         return IfFold([&]() { return Builder.CreateSub(LogX, Y); });
1597   }
1598 
1599   // log2(X & Y) -> either log2(X) or log2(Y)
1600   // This requires `AssumeNonZero` as `X & Y` may be zero when X != Y.
1601   if (AssumeNonZero && match(Op, m_And(m_Value(X), m_Value(Y)))) {
1602     if (Value *LogX = takeLog2(X, Depth, AssumeNonZero, DoFold))
1603       return IfFold([&]() { return LogX; });
1604     if (Value *LogY = takeLog2(Y, Depth, AssumeNonZero, DoFold))
1605       return IfFold([&]() { return LogY; });
1606   }
1607 
1608   // log2(Cond ? X : Y) -> Cond ? log2(X) : log2(Y)
1609   // FIXME: Require one use?
1610   if (SelectInst *SI = dyn_cast<SelectInst>(Op))
1611     if (Value *LogX = takeLog2(SI->getOperand(1), Depth, AssumeNonZero, DoFold))
1612       if (Value *LogY =
1613               takeLog2(SI->getOperand(2), Depth, AssumeNonZero, DoFold))
1614         return IfFold([&]() {
1615           return Builder.CreateSelect(SI->getOperand(0), LogX, LogY, "",
1616                                       ProfcheckDisableMetadataFixes ? nullptr
1617                                                                     : SI);
1618         });
1619 
1620   // log2(umin(X, Y)) -> umin(log2(X), log2(Y))
1621   // log2(umax(X, Y)) -> umax(log2(X), log2(Y))
1622   auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op);
1623   if (MinMax && MinMax->hasOneUse() && !MinMax->isSigned()) {
1624     // Use AssumeNonZero as false here. Otherwise we can hit case where
1625     // log2(umax(X, Y)) != umax(log2(X), log2(Y)) (because overflow).
1626     if (Value *LogX = takeLog2(MinMax->getLHS(), Depth,
1627                                /*AssumeNonZero*/ false, DoFold))
1628       if (Value *LogY = takeLog2(MinMax->getRHS(), Depth,
1629                                  /*AssumeNonZero*/ false, DoFold))
1630         return IfFold([&]() {
1631           return Builder.CreateBinaryIntrinsic(MinMax->getIntrinsicID(), LogX,
1632                                                LogY);
1633         });
1634   }
1635 
1636   return nullptr;
1637 }
