2493 Instruction *InstCombinerImpl::visitSRem(BinaryOperator &I) {
2494   if (Value *V = simplifySRemInst(I.getOperand(0), I.getOperand(1),
2495                                   SQ.getWithInstruction(&I)))
2496     return replaceInstUsesWith(I, V);
2497 
2498   if (Instruction *X = foldVectorBinop(I))
2499     return X;
2500 
2501   // Handle the integer rem common cases
2502   if (Instruction *Common = commonIRemTransforms(I))
2503     return Common;
2504 
2505   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
2506   {
2507     const APInt *Y;
2508     // X % -Y -> X % Y
2509     if (match(Op1, m_Negative(Y)) && !Y->isMinSignedValue())
2510       return replaceOperand(I, 1, ConstantInt::get(I.getType(), -*Y));
2511   }
2512 
2513   // -X srem Y --> -(X srem Y)
2514   Value *X, *Y;
2515   if (match(&I, m_SRem(m_OneUse(m_NSWNeg(m_Value(X))), m_Value(Y))))
2516     return BinaryOperator::CreateNSWNeg(Builder.CreateSRem(X, Y));
2517 
2518   // If the sign bits of both operands are zero (i.e. we can prove they are
2519   // unsigned inputs), turn this into a urem.
2520   APInt Mask(APInt::getSignMask(I.getType()->getScalarSizeInBits()));
2521   if (MaskedValueIsZero(Op1, Mask, &I) && MaskedValueIsZero(Op0, Mask, &I)) {
2522     // X srem Y -> X urem Y, iff X and Y don't have sign bit set
2523     return BinaryOperator::CreateURem(Op0, Op1, I.getName());
2524   }
2525 
2526   // If it's a constant vector, flip any negative values positive.
2527   if (isa<ConstantVector>(Op1) || isa<ConstantDataVector>(Op1)) {
2528     Constant *C = cast<Constant>(Op1);
2529     unsigned VWidth = cast<FixedVectorType>(C->getType())->getNumElements();
2530 
2531     bool hasNegative = false;
2532     bool hasMissing = false;
2533     for (unsigned i = 0; i != VWidth; ++i) {
2534       Constant *Elt = C->getAggregateElement(i);
2535       if (!Elt) {
2536         hasMissing = true;
2537         break;
2538       }
2539 
2540       if (ConstantInt *RHS = dyn_cast<ConstantInt>(Elt))
2541         if (RHS->isNegative())
2542           hasNegative = true;
2543     }
2544 
2545     if (hasNegative && !hasMissing) {
2546       SmallVector<Constant *, 16> Elts(VWidth);
2547       for (unsigned i = 0; i != VWidth; ++i) {
2548         Elts[i] = C->getAggregateElement(i);  // Handle undef, etc.
2549         if (ConstantInt *RHS = dyn_cast<ConstantInt>(Elts[i])) {
2550           if (RHS->isNegative())
2551             Elts[i] = cast<ConstantInt>(ConstantExpr::getNeg(RHS));
2552         }
2553       }
2554 
2555       Constant *NewRHSV = ConstantVector::get(Elts);
2556       if (NewRHSV != C)  // Don't loop on -MININT
2557         return replaceOperand(I, 1, NewRHSV);
2558     }
2559   }
2560 
