1021 // match variations of a^2 + 2*a*b + b^2
1022 //
1023 // to reuse the code between the FP and Int versions, the instruction OpCodes
1024 //  and constant types have been turned into template parameters.
1025 //
1026 // Mul2Rhs: The constant to perform the multiplicative equivalent of X*2 with;
1027 //  should be `m_SpecificFP(2.0)` for FP and `m_SpecificInt(1)` for Int
1028 //  (we're matching `X<<1` instead of `X*2` for Int)
1029 template <bool FP, typename Mul2Rhs>
1030 static bool matchesSquareSum(BinaryOperator &I, Mul2Rhs M2Rhs, Value *&A,
1031                              Value *&B) {
1032   constexpr unsigned MulOp = FP ? Instruction::FMul : Instruction::Mul;
1033   constexpr unsigned AddOp = FP ? Instruction::FAdd : Instruction::Add;
1034   constexpr unsigned Mul2Op = FP ? Instruction::FMul : Instruction::Shl;
1035 
1036   // (a * a) + (((a * 2) + b) * b)
1037   if (match(&I, m_c_BinOp(
1038                     AddOp, m_OneUse(m_BinOp(MulOp, m_Value(A), m_Deferred(A))),
1039                     m_OneUse(m_c_BinOp(
1040                         MulOp,
1041                         m_c_BinOp(AddOp, m_BinOp(Mul2Op, m_Deferred(A), M2Rhs),
1042                                   m_Value(B)),
1043                         m_Deferred(B))))))
1044     return true;
1045 
1046   // ((a * b) * 2)  or ((a * 2) * b)
1047   // +
1048   // (a * a + b * b) or (b * b + a * a)
1049   return match(
1050       &I, m_c_BinOp(
1051               AddOp,
1052               m_CombineOr(
1053                   m_OneUse(m_BinOp(
1054                       Mul2Op, m_BinOp(MulOp, m_Value(A), m_Value(B)), M2Rhs)),
1055                   m_OneUse(m_c_BinOp(MulOp, m_BinOp(Mul2Op, m_Value(A), M2Rhs),
1056                                      m_Value(B)))),
1057               m_OneUse(
1058                   m_c_BinOp(AddOp, m_BinOp(MulOp, m_Deferred(A), m_Deferred(A)),
1059                             m_BinOp(MulOp, m_Deferred(B), m_Deferred(B))))));
1060 }
