1062 // Fold integer variations of a^2 + 2*a*b + b^2 -> (a + b)^2
1063 Instruction *InstCombinerImpl::foldSquareSumInt(BinaryOperator &I) {
1064   Value *A, *B;
1065   if (matchesSquareSum</*FP*/ false>(I, m_SpecificInt(1), A, B)) {
1066     Value *AB = Builder.CreateAdd(A, B);
1067     return BinaryOperator::CreateMul(AB, AB);
1068   }
1069   return nullptr;
