8656 static Instruction *foldFCmpFSubIntoFCmp(FCmpInst &I, Instruction *LHSI,
8657                                          Constant *RHSC, InstCombinerImpl &CI) {
8658   const CmpInst::Predicate Pred = I.getPredicate();
8659   Value *X = LHSI->getOperand(0);
8660   Value *Y = LHSI->getOperand(1);
8661   switch (Pred) {
8662   default:
8663     break;
8664   case FCmpInst::FCMP_UGT:
8665   case FCmpInst::FCMP_ULT:
8666   case FCmpInst::FCMP_UNE:
8667   case FCmpInst::FCMP_OEQ:
8668   case FCmpInst::FCMP_OGE:
8669   case FCmpInst::FCMP_OLE:
8670     // The optimization is not valid if X and Y are infinities of the same
8671     // sign, i.e. the inf - inf = nan case. If the fsub has the ninf or nnan
8672     // flag then we can assume we do not have that case. Otherwise we might be
8673     // able to prove that either X or Y is not infinity.
8674     if (!LHSI->hasNoNaNs() && !LHSI->hasNoInfs() &&
8675         !isKnownNeverInfinity(Y,
8676                               CI.getSimplifyQuery().getWithInstruction(&I)) &&
8677         !isKnownNeverInfinity(X, CI.getSimplifyQuery().getWithInstruction(&I)))
8678       break;
8679 
8680     [[fallthrough]];
8681   case FCmpInst::FCMP_OGT:
8682   case FCmpInst::FCMP_OLT:
8683   case FCmpInst::FCMP_ONE:
8684   case FCmpInst::FCMP_UEQ:
8685   case FCmpInst::FCMP_UGE:
8686   case FCmpInst::FCMP_ULE:
8687     // fcmp pred (x - y), 0 --> fcmp pred x, y
8688     if (match(RHSC, m_AnyZeroFP()) &&
8689         I.getFunction()->getDenormalMode(
8690             LHSI->getType()->getScalarType()->getFltSemantics()) ==
8691             DenormalMode::getIEEE()) {
8692       CI.replaceOperand(I, 0, X);
8693       CI.replaceOperand(I, 1, Y);
8694       I.setHasNoInfs(LHSI->hasNoInfs());
8695       if (LHSI->hasNoNaNs())
8696         I.setHasNoNaNs(true);
8697       return &I;
8698     }
8699     break;
8700   }
8701 
8702   return nullptr;
8703 }
