8774 /// Returns true if a select that implements a min/max is redundant and
8775 /// select result can be replaced with its non-constant operand, e.g.,
8776 ///   select ( (si/ui-to-fp A) <= C ), C, (si/ui-to-fp A)
8777 /// where C is the FP constant equal to the minimum integer value
8778 /// representable by A.
8779 static bool isMinMaxCmpSelectEliminable(SelectPatternFlavor Flavor, Value *A,
8780                                         Value *B) {
8781   const APFloat *APF;
8782   if (!match(B, m_APFloat(APF)))
8783     return false;
8784 
8785   auto *I = dyn_cast<Instruction>(A);
8786   if (!I || !(I->getOpcode() == Instruction::SIToFP ||
8787               I->getOpcode() == Instruction::UIToFP))
8788     return false;
8789 
8790   bool IsUnsigned = I->getOpcode() == Instruction::UIToFP;
8791   unsigned BitWidth = I->getOperand(0)->getType()->getScalarSizeInBits();
8792   APSInt IntBoundary = (Flavor == SPF_FMAXNUM)
8793                            ? APSInt::getMinValue(BitWidth, IsUnsigned)
8794                            : APSInt::getMaxValue(BitWidth, IsUnsigned);
8795   APSInt ConvertedInt(BitWidth, IsUnsigned);
8796   bool IsExact;
8797   APFloat::opStatus Status =
8798       APF->convertToInteger(ConvertedInt, APFloat::rmTowardZero, &IsExact);
8799   return Status == APFloat::opOK && IsExact && ConvertedInt == IntBoundary;
8800 }
