537             });
538         if (VectorOps == 1) {
539           Value *NewPtr = GEP->getPointerOperand();
540           if (isa<VectorType>(NewPtr->getType()))
541             NewPtr = Builder.CreateExtractElement(NewPtr, IndexC);
542 
543           SmallVector<Value *> NewOps;
544           for (unsigned I = 1; I != GEP->getNumOperands(); ++I) {
