2770   Value *Cond;
2771   Constant *TrueC, *FalseC;
2772   if (!match(GEP.getPointerOperand(), m_Instruction(Sel)) ||
2773       !match(Sel,
2774              m_Select(m_Value(Cond), m_Constant(TrueC), m_Constant(FalseC))))
2775     return nullptr;
2776 
2777   // gep (select Cond, TrueC, FalseC), IndexC --> select Cond, TrueC', FalseC'
2778   // Propagate 'inbounds' and metadata from existing instructions.
2779   // Note: using IRBuilder to create the constants for efficiency.
2780   SmallVector<Value *, 4> IndexC(GEP.indices());
2781   GEPNoWrapFlags NW = GEP.getNoWrapFlags();
2782   Type *Ty = GEP.getSourceElementType();
2783   Value *NewTrueC = Builder.CreateGEP(Ty, TrueC, IndexC, "", NW);
2784   Value *NewFalseC = Builder.CreateGEP(Ty, FalseC, IndexC, "", NW);
2785   return SelectInst::Create(Cond, NewTrueC, NewFalseC, "", nullptr, Sel);
2786 }
