2788 // Canonicalization:
2789 // gep T, (gep i8, base, C1), (Index + C2) into
2790 // gep T, (gep i8, base, C1 + C2 * sizeof(T)), Index
2791 static Instruction *canonicalizeGEPOfConstGEPI8(GetElementPtrInst &GEP,
2792                                                 GEPOperator *Src,
2793                                                 InstCombinerImpl &IC) {
2794   if (GEP.getNumIndices() != 1)
2795     return nullptr;
2796   auto &DL = IC.getDataLayout();
2797   Value *Base;
2798   const APInt *C1;
2799   if (!match(Src, m_PtrAdd(m_Value(Base), m_APInt(C1))))
2800     return nullptr;
2801   Value *VarIndex;
2802   const APInt *C2;
2803   Type *PtrTy = Src->getType()->getScalarType();
2804   unsigned IndexSizeInBits = DL.getIndexTypeSizeInBits(PtrTy);
2805   if (!match(GEP.getOperand(1), m_AddLike(m_Value(VarIndex), m_APInt(C2))))
2806     return nullptr;
2807   if (C1->getBitWidth() != IndexSizeInBits ||
2808       C2->getBitWidth() != IndexSizeInBits)
2809     return nullptr;
2810   Type *BaseType = GEP.getSourceElementType();
2811   if (isa<ScalableVectorType>(BaseType))
2812     return nullptr;
2813   APInt TypeSize(IndexSizeInBits, DL.getTypeAllocSize(BaseType));
2814   APInt NewOffset = TypeSize * *C2 + *C1;
2815   if (NewOffset.isZero() ||
2816       (Src->hasOneUse() && GEP.getOperand(1)->hasOneUse())) {
2817     GEPNoWrapFlags Flags = GEPNoWrapFlags::none();
2818     if (GEP.hasNoUnsignedWrap() &&
2819         cast<GEPOperator>(Src)->hasNoUnsignedWrap() &&
2820         match(GEP.getOperand(1), m_NUWAddLike(m_Value(), m_Value()))) {
2821       Flags |= GEPNoWrapFlags::noUnsignedWrap();
2822       if (GEP.isInBounds() && cast<GEPOperator>(Src)->isInBounds())
2823         Flags |= GEPNoWrapFlags::inBounds();
2824     }
2825 
2826     Value *GEPConst =
2827         IC.Builder.CreatePtrAdd(Base, IC.Builder.getInt(NewOffset), "", Flags);
2828     return GetElementPtrInst::Create(BaseType, GEPConst, VarIndex, Flags);
2829   }
2830 
2831   return nullptr;
2832 }
