2834 /// Combine constant offsets separated by variable offsets.
2835 /// ptradd (ptradd (ptradd p, C1), x), C2 -> ptradd (ptradd p, x), C1+C2
2836 static Instruction *combineConstantOffsets(GetElementPtrInst &GEP,
2837                                            InstCombinerImpl &IC) {
2838   if (!GEP.hasAllConstantIndices())
2839     return nullptr;
2840 
2841   GEPNoWrapFlags NW = GEPNoWrapFlags::all();
2842   SmallVector<GetElementPtrInst *> Skipped;
2843   auto *InnerGEP = dyn_cast<GetElementPtrInst>(GEP.getPointerOperand());
2844   while (true) {
2845     if (!InnerGEP)
2846       return nullptr;
2847 
2848     NW = NW.intersectForReassociate(InnerGEP->getNoWrapFlags());
2849     if (InnerGEP->hasAllConstantIndices())
2850       break;
2851 
2852     if (!InnerGEP->hasOneUse())
2853       return nullptr;
2854 
2855     Skipped.push_back(InnerGEP);
2856     InnerGEP = dyn_cast<GetElementPtrInst>(InnerGEP->getPointerOperand());
2857   }
2858 
2859   // The two constant offset GEPs are directly adjacent: Let normal offset
2860   // merging handle it.
2861   if (Skipped.empty())
2862     return nullptr;
2863 
2864   // FIXME: This one-use check is not strictly necessary. Consider relaxing it
2865   // if profitable.
2866   if (!InnerGEP->hasOneUse())
2867     return nullptr;
2868 
2869   // Don't bother with vector splats.
2870   Type *Ty = GEP.getType();
2871   if (InnerGEP->getType() != Ty)
2872     return nullptr;
2873 
2874   const DataLayout &DL = IC.getDataLayout();
2875   APInt Offset(DL.getIndexTypeSizeInBits(Ty), 0);
2876   if (!GEP.accumulateConstantOffset(DL, Offset) ||
2877       !InnerGEP->accumulateConstantOffset(DL, Offset))
2878     return nullptr;
2879 
2880   IC.replaceOperand(*Skipped.back(), 0, InnerGEP->getPointerOperand());
2881   for (GetElementPtrInst *SkippedGEP : Skipped)
2882     SkippedGEP->setNoWrapFlags(NW);
2883 
2884   return IC.replaceInstUsesWith(
2885       GEP,
2886       IC.Builder.CreatePtrAdd(Skipped.front(), IC.Builder.getInt(Offset), "",
2887                               NW.intersectForOffsetAdd(GEP.getNoWrapFlags())));
2888 }
