2890 Instruction *InstCombinerImpl::visitGEPOfGEP(GetElementPtrInst &GEP,
2891                                              GEPOperator *Src) {
2892   // Combine Indices - If the source pointer to this getelementptr instruction
2893   // is a getelementptr instruction with matching element type, combine the
2894   // indices of the two getelementptr instructions into a single instruction.
2895   if (!shouldMergeGEPs(*cast<GEPOperator>(&GEP), *Src))
2896     return nullptr;
2897 
2898   if (auto *I = canonicalizeGEPOfConstGEPI8(GEP, Src, *this))
2899     return I;
2900 
2901   if (auto *I = combineConstantOffsets(GEP, *this))
2902     return I;
2903 
2904   if (Src->getResultElementType() != GEP.getSourceElementType())
2905     return nullptr;
2906 
2907   // Fold chained GEP with constant base into single GEP:
2908   // gep i8, (gep i8, %base, C1), (select Cond, C2, C3)
2909   // -> gep i8, %base, (select Cond, C1+C2, C1+C3)
2910   if (Src->hasOneUse() && GEP.getNumIndices() == 1 &&
2911       Src->getNumIndices() == 1) {
2912     Value *SrcIdx = *Src->idx_begin();
2913     Value *GEPIdx = *GEP.idx_begin();
2914     const APInt *ConstOffset, *TrueVal, *FalseVal;
2915     Value *Cond;
2916 
2917     if ((match(SrcIdx, m_APInt(ConstOffset)) &&
2918          match(GEPIdx,
2919                m_Select(m_Value(Cond), m_APInt(TrueVal), m_APInt(FalseVal)))) ||
2920         (match(GEPIdx, m_APInt(ConstOffset)) &&
2921          match(SrcIdx,
2922                m_Select(m_Value(Cond), m_APInt(TrueVal), m_APInt(FalseVal))))) {
2923       auto *Select = isa<SelectInst>(GEPIdx) ? cast<SelectInst>(GEPIdx)
2924                                              : cast<SelectInst>(SrcIdx);
2925 
2926       // Make sure the select has only one use.
2927       if (!Select->hasOneUse())
2928         return nullptr;
2929 
2930       if (TrueVal->getBitWidth() != ConstOffset->getBitWidth() ||
2931           FalseVal->getBitWidth() != ConstOffset->getBitWidth())
2932         return nullptr;
2933 
2934       APInt NewTrueVal = *ConstOffset + *TrueVal;
2935       APInt NewFalseVal = *ConstOffset + *FalseVal;
2936       Constant *NewTrue = ConstantInt::get(Select->getType(), NewTrueVal);
2937       Constant *NewFalse = ConstantInt::get(Select->getType(), NewFalseVal);
2938       Value *NewSelect = Builder.CreateSelect(
2939           Cond, NewTrue, NewFalse, /*Name=*/"",
2940           /*MDFrom=*/(ProfcheckDisableMetadataFixes ? nullptr : Select));
2941       GEPNoWrapFlags Flags =
2942           getMergedGEPNoWrapFlags(*Src, *cast<GEPOperator>(&GEP));
2943       return replaceInstUsesWith(GEP,
2944                                  Builder.CreateGEP(GEP.getResultElementType(),
2945                                                    Src->getPointerOperand(),
2946                                                    NewSelect, "", Flags));
2947     }
2948   }
2949 
2950   // Find out whether the last index in the source GEP is a sequential idx.
2951   bool EndsWithSequential = false;
2952   for (gep_type_iterator I = gep_type_begin(*Src), E = gep_type_end(*Src);
2953        I != E; ++I)
2954     EndsWithSequential = I.isSequential();
2955   if (!EndsWithSequential)
2956     return nullptr;
2957 
2958   // Replace: gep (gep %P, long B), long A, ...
2959   // With:    T = long A+B; gep %P, T, ...
2960   Value *SO1 = Src->getOperand(Src->getNumOperands() - 1);
2961   Value *GO1 = GEP.getOperand(1);
2962 
2963   // If they aren't the same type, then the input hasn't been processed
2964   // by the loop above yet (which canonicalizes sequential index types to
2965   // intptr_t).  Just avoid transforming this until the input has been
2966   // normalized.
2967   if (SO1->getType() != GO1->getType())
2968     return nullptr;
2969 
2970   Value *Sum =
2971       simplifyAddInst(GO1, SO1, false, false, SQ.getWithInstruction(&GEP));
2972   // Only do the combine when we are sure the cost after the
2973   // merge is never more than that before the merge.
2974   if (Sum == nullptr)
2975     return nullptr;
2976 
2977   SmallVector<Value *, 8> Indices;
2978   Indices.append(Src->op_begin() + 1, Src->op_end() - 1);
2979   Indices.push_back(Sum);
2980   Indices.append(GEP.op_begin() + 2, GEP.op_end());
2981 
2982   // Don't create GEPs with more than one non-zero index.
2983   unsigned NumNonZeroIndices = count_if(Indices, [](Value *Idx) {
2984     auto *C = dyn_cast<Constant>(Idx);
2985     return !C || !C->isNullValue();
2986   });
2987   if (NumNonZeroIndices > 1)
2988     return nullptr;
2989 
2990   return replaceInstUsesWith(
2991       GEP, Builder.CreateGEP(
2992                Src->getSourceElementType(), Src->getOperand(0), Indices, "",
2993                getMergedGEPNoWrapFlags(*Src, *cast<GEPOperator>(&GEP))));
2994 }
